const getGSTByHSN = (HSN_CODE) => {
  const hsnData = HSN_CODES_WITH_RATE.find(
    (item) => item.hsn_code === HSN_CODE
  );

  if (!hsnData) {
    return 0;
  }

  let rate = Number(hsnData?.igst);

  if (!rate || rate === "" || rate === "0" || rate === 0) {
    rate = Number(hsnData?.cgst) + Number(hsnData?.sgst);
  }

  //  if rate is NaN or undefined, return 0
  if (isNaN(rate) || rate === undefined) {
    return 0;
  }

  return Number(rate);
};

module.exports = { getGSTByHSN };
